class TokenAdapter(...) : TokenPort {
    override fun generateAccessToken(userId: Long): String {
        return Jwts.builder().subject(userId.toString()).claim("type", "access")
            .issuedAt(now).expiration(Date(now.time + accessTokenExpiry)).signWith(key).compact()
    }
}

class GoogleOAuthClient(...) : OAuthClientPort {
    override fun exchangeCodeForToken(authCode: String, redirectUri: String): OAuthTokenResult {
        val response = webClient.post().uri("https://oauth2.googleapis.com/token")
            .body(BodyInserters.fromFormData("grant_type", "authorization_code").with("code", authCode)...)
    }
}

class KakaoOAuthClient(...) : OAuthClientPort {
    override fun exchangeCodeForToken(authCode: String, redirectUri: String): OAuthTokenResult {
        webClient.post().uri("https://kauth.kakao.com/oauth/token")...
    }
}

@Bean
fun oauthClients(
    @Qualifier("kakaoOAuthClient") kakaoClient: OAuthClientPort,
    @Qualifier("googleOAuthClient") googleClient: OAuthClientPort
): Map<AuthProvider, OAuthClientPort> = mapOf(
    AuthProvider.KAKAO to kakaoClient,
    AuthProvider.GOOGLE to googleClient
)
